// ============================================================
// BUILD WATCHLIST & CHECK MARKET HOURS
// Edit 'watchlist', 'timeframe', 'lookbackBars' as needed.
// ============================================================
const watchlist = ['TSLA', 'NVDA', 'SPY'];
const timeframe = '5Min'; // 1Min | 5Min | 15Min | 1Hour
const lookbackBars = 50;
const newsItemsPerTicker = 5;

// Market hours gate (Eastern Time, Mon-Fri 09:30-15:45)
const now = new Date();
const etStr = now.toLocaleString('en-US', { timeZone: 'America/New_York' });
const etTime = new Date(etStr);
const day = etTime.getDay(); // 0=Sun,6=Sat
const totalMin = etTime.getHours() * 60 + etTime.getMinutes();
const isOpen = day >= 1 && day <= 5 && totalMin >= 570 && totalMin <= 945;

if (!isOpen) {
  // Return empty — downstream nodes will have nothing to process
  return [];
}

return watchlist.map(symbol => ({
  json: { symbol, timeframe, lookbackBars, newsItemsPerTicker, runAt: now.toISOString() }
}));

// ============================================================
// MERGE BARS + NEWS  →  COMPUTE INDICATORS
// Receives items from both Fetch Bars and Fetch News.
// Groups by symbol, then computes SMA20 / EMA9 / RSI14 / MACD.
// ============================================================

function sma(values, period) {
  const out = [];
  for (let i = period - 1; i < values.length; i++) {
    const sl = values.slice(i - period + 1, i + 1);
    out.push(sl.reduce((a, b) => a + b, 0) / period);
  }
  return out;
}

function ema(values, period) {
  if (values.length < period) return [];
  const k = 2 / (period + 1);
  let prev = values.slice(0, period).reduce((a, b) => a + b, 0) / period;
  const out = [prev];
  for (let i = period; i < values.length; i++) {
    prev = values[i] * k + prev * (1 - k);
    out.push(prev);
  }
  return out;
}

function rsi(closes, period) {
  if (closes.length < period + 1) return [];
  const gains = [], losses = [];
  for (let i = 1; i < closes.length; i++) {
    const d = closes[i] - closes[i - 1];
    gains.push(d > 0 ? d : 0);
    losses.push(d < 0 ? Math.abs(d) : 0);
  }
  let ag = gains.slice(0, period).reduce((a, b) => a + b, 0) / period;
  let al = losses.slice(0, period).reduce((a, b) => a + b, 0) / period;
  const out = [al === 0 ? 100 : 100 - 100 / (1 + ag / al)];
  for (let i = period; i < gains.length; i++) {
    ag = (ag * (period - 1) + gains[i]) / period;
    al = (al * (period - 1) + losses[i]) / period;
    out.push(al === 0 ? 100 : 100 - 100 / (1 + ag / al));
  }
  return out;
}

const last = arr => arr[arr.length - 1];
const items = $input.all();

// Each item comes from either the bars node or the news node.
// Both carry $json.symbol from the watchlist run.
const bySymbol = {};
for (const item of items) {
  const sym = item.json.symbol;
  if (!bySymbol[sym]) bySymbol[sym] = { bars: [], news: [] };
  if (item.json.bars)  bySymbol[sym].bars = item.json.bars;
  if (item.json.news)  bySymbol[sym].news = item.json.news;
}

const results = [];
for (const [symbol, data] of Object.entries(bySymbol)) {
  const bars   = data.bars  || [];
  const news   = data.news  || [];
  if (bars.length === 0) continue;

  const closes  = bars.map(b => b.c);
  const sma20   = sma(closes, 20);
  const ema9    = ema(closes, 9);
  const rsi14   = rsi(closes, 14);
  const fastEma = ema(closes, 12);
  const slowEma = ema(closes, 26);
  const offset  = 26 - 12;
  const macdLine   = slowEma.map((v, i) => fastEma[i + offset] - v);
  const macdSignal = ema(macdLine, 9);

  const recentCandles = bars.slice(-10).map(b => ({
    timestamp: b.t, open: b.o, high: b.h, low: b.l, close: b.c, volume: b.v
  }));
  const recentNews = news.slice(0, 3).map(n => ({
    headline: n.headline, source: n.source, publishedAt: n.created_at
  }));

  results.push({ json: {
    symbol,
    currentPrice: last(closes),
    recentCandles,
    recentNews,
    latestIndicators: {
      sma20:      last(sma20)?.toFixed(2),
      ema9:       last(ema9)?.toFixed(2),
      rsi14:      last(rsi14)?.toFixed(1),
      macd:       last(macdLine)?.toFixed(4),
      macdSignal: last(macdSignal)?.toFixed(4)
    }
  }});
}

return results;

// ============================================================
// AGGREGATE CONTEXTS  →  BUILD LLM PROMPT PAYLOAD
// Collects all ticker results into a single Anthropic API call.
// ============================================================
const items   = $input.all();
const contexts = items.map(i => i.json);

const contextBlock = contexts.map(ctx => {
  const ind = ctx.latestIndicators || {};
  const candles = (ctx.recentCandles || []).slice(-5)
    .map(c => `  ${(c.timestamp||'').substring(11,16)} O:${c.open?.toFixed(2)} H:${c.high?.toFixed(2)} L:${c.low?.toFixed(2)} C:${c.close?.toFixed(2)} V:${c.volume}`)
    .join('\n');
  const newsLines = (ctx.recentNews || [])
    .map(n => `  [${n.source}] ${n.headline}`)
    .join('\n') || '  No recent news.';

  return `=== ${ctx.symbol} ===\nPrice: $${ctx.currentPrice?.toFixed(2)}\nSMA20: ${ind.sma20}  EMA9: ${ind.ema9}  RSI14: ${ind.rsi14}\nMACD: ${ind.macd}  Signal: ${ind.macdSignal}\nLast 5 candles:\n${candles}\nRecent news:\n${newsLines}`;
}).join('\n\n---\n\n');

const systemPrompt = `You are an expert intraday trader AI. RULES: no leverage, max 5% position size per ticker, always include stop-loss and take-profit, prefer HOLD when uncertain. Output ONLY valid JSON — no markdown, no extra text.`;

const userPrompt = `Analyze these ${contexts.length} tickers and return trading decisions.\n\n${contextBlock}\n\nRespond ONLY with this exact JSON schema:\n{"decisions":[{"symbol":"...","action":"BUY|SELL|HOLD","position_size_pct":0-5,"stop_loss_pct":0.5-5,"take_profit_pct":0.5-10,"confidence":0-1,"reason":"1-2 sentence rationale"}]}`;

return [{ json: {
  contexts,
  anthropicPayload: {
    model:      $vars.LLM_MODEL  || 'claude-opus-4-6',
    max_tokens: 2048,
    temperature: 0.1,
    system:   systemPrompt,
    messages: [{ role: 'user', content: userPrompt }]
  }
}}];

// ============================================================
// PARSE LLM RESPONSE  +  RISK VALIDATION
// Only passes BUY/SELL decisions that meet confidence threshold.
// ============================================================
const item = $input.first();
const rawText = item.json?.content?.[0]?.text || '{"decisions":[]}';

// Strip markdown fences the model sometimes adds
const cleaned = rawText.replace(/```json\s*/gi,'').replace(/```\s*/g,'').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  console.error('LLM JSON parse error:', e.message);
  console.error('Raw (first 300 chars):', rawText.substring(0,300));
  return [];
}

// Risk thresholds — edit here or drive from n8n Variables
const MIN_CONFIDENCE  = parseFloat($vars.MIN_CONFIDENCE  || '0.65');
const MAX_POSITION_PCT = parseFloat($vars.MAX_POSITION_PCT || '5');

const results = [];
for (const d of (parsed.decisions || [])) {
  const action     = (d.action || '').toUpperCase();
  const confidence = Math.max(0, Math.min(1,  Number(d.confidence)        || 0));
  const sizePct    = Math.max(0, Math.min(MAX_POSITION_PCT, Number(d.position_size_pct) || 0));
  const slPct      = Math.max(0.1, Math.min(10, Number(d.stop_loss_pct)   || 1));
  const tpPct      = Math.max(0.1, Math.min(20, Number(d.take_profit_pct) || 1));

  if (!['BUY','SELL','HOLD'].includes(action)) { console.log(`SKIP ${d.symbol}: bad action`);   continue; }
  if (action === 'HOLD')                        { console.log(`SKIP ${d.symbol}: HOLD`);          continue; }
  if (confidence < MIN_CONFIDENCE)              { console.log(`SKIP ${d.symbol}: low confidence ${confidence}`); continue; }

  results.push({ json: {
    symbol:         d.symbol,
    action,
    confidence,
    positionSizePct: sizePct,
    stopLossPct:     slPct,
    takeProfitPct:   tpPct,
    reason:          (d.reason || '').substring(0, 300),
    rawOutput:       rawText
  }});
}

console.log(`[Risk] Actionable decisions: ${results.length}`);
return results;

// ============================================================
// BUILD ALPACA BRACKET ORDER PAYLOAD
// Derives qty from equity % and current price.
// ============================================================
const d = $json;

// Fetch live equity from your backend /api/pnl, or use the fallback variable
const accountEquity = parseFloat($vars.ACCOUNT_EQUITY_FALLBACK || '100000');
const currentPrice  = parseFloat(d.currentPrice || 100);
const orderValue    = (d.positionSizePct / 100) * accountEquity;
const qty           = Math.floor(orderValue / currentPrice);

if (qty <= 0) {
  console.log(`[Order] ${d.symbol}: qty ${qty} too small — skipping`);
  return [];
}

const side = d.action === 'BUY' ? 'buy' : 'sell';
const stopPrice = side === 'buy'
  ? currentPrice * (1 - d.stopLossPct   / 100)
  : currentPrice * (1 + d.stopLossPct   / 100);
const tpPrice = side === 'buy'
  ? currentPrice * (1 + d.takeProfitPct / 100)
  : currentPrice * (1 - d.takeProfitPct / 100);

return [{ json: {
  ...d,
  orderPayload: {
    symbol:         d.symbol,
    qty:            String(qty),
    side,
    type:           'market',
    time_in_force:  'day',
    order_class:    'bracket',
    stop_loss:      { stop_price:  stopPrice.toFixed(2) },
    take_profit:    { limit_price: tpPrice.toFixed(2)   }
  }
}}];
